**วิธีดึง `customer_id` จาก JSON ที่ให้มา**  

ต่อไปนี้เป็นตัวอย่างโค้ด **Python** ที่ทำตามเงื่อนไขที่คุณต้องการ  

1. ถ้า JSON เป็นอาร์เรย์ธรรมดา (อย่างที่คุณส่งมา)  
2. ถ้า JSON มีโครงสร้างแบบ  
   ```json
   {
       "content": [
           {
               "type": "text",
               "text": "{ \"rows\": [ { ... } ] }"
           }
       ]
   }
   ```  
   – จะต้องดึง `text` ก็อปปี้แล้ว `json.loads()` อีกครั้งเพื่อให้ได้ข้อมูลจริง  

```python
import json
from typing import Any, List, Dict, Union

# -------------------------------------------------
# 1️⃣ ฟังก์ชันช่วย: แปลงข้อมูลที่อาจอยู่ใน content.text ให้เป็น Python object
# -------------------------------------------------
def _extract_from_content(data: Dict) -> Union[List[Dict], None]:
    """
    ถ้า data มี key 'content' แบบที่อธิบายไว้
    จะดึงข้อความ JSON ที่อยู่ใน content[0]['text'] และแปลงเป็น Python object
    คืนค่าเป็น list ของ dict (หรือ None ถ้าแปลงไม่ได้)
    """
    if not isinstance(data, dict):
        return None

    content = data.get("content")
    if not isinstance(content, list) or not content:
        return None

    # เราคาดว่า element แรกเป็น object ที่มี type='text' และมี key 'text'
    txt_obj = next((c for c in content if isinstance(c, dict) and c.get("type") == "text"), None)
    if not txt_obj:
        return None

    raw_text = txt_obj.get("text")
    if not isinstance(raw_text, str):
        return None

    try:
        # raw_text คือ JSON string (เช่น "{ \"rows\": [ {...} ] }")
        inner = json.loads(raw_text)
        # ปกติข้อมูลจะอยู่ใน key ที่ชื่อว่า "rows" หรือ "data" …
        # เราจะพยายามดึง list ของ rows ทั้งหมด
        if isinstance(inner, dict):
            # ค้นหา key ที่มีค่าเป็น list ของ dict (เช่น rows, data, items …)
            for possible_key, value in inner.items():
                if isinstance(value, list) and all(isinstance(i, dict) for i in value):
                    return value
        elif isinstance(inner, list):
            # ถ้าเป็น list ตรง ๆ
            return inner
    except json.JSONDecodeError:
        return None

    return None


# -------------------------------------------------
# 2️⃣ ฟังก์ชันหลัก: รับ JSON (อาจเป็น string หรือ dict) → คืนค่า customer_id ที่ตรงกับชื่อที่กำหนด
# -------------------------------------------------
def get_customer_id(
    raw_json: Union[str, dict, list],
    target_name: str = "สมชาย ใจดี"
) -> int | None:
    """
    คืนค่า customer_id ของลูกค้าที่มี `name` ตรงกับ `target_name`
    หากไม่พบหรือข้อมูลไม่อยู่ในรูปแบบที่คาดไว้ จะคืนค่า None
    """
    # 1️⃣ แปลงเป็น Python object ถ้าเป็น string
    if isinstance(raw_json, str):
        try:
            data = json.loads(raw_json)
        except json.JSONDecodeError as e:
            raise ValueError(f"ข้อมูล JSON ที่ให้นั้นไม่สามารถแปลงได้: {e}")
    else:
        data = raw_json

    # 2️⃣ ตรวจสอบว่า data เป็น list (กรณีที่คุณให้มาโดยตรง)
    rows: List[Dict] = []
    if isinstance(data, list):
        rows = data                     # ตัวอย่างที่คุณให้คือ list ของ dict
    elif isinstance(data, dict):
        # 3️⃣ ตรวจสอบว่าเป็นโครงสร้างแบบ content.text
        extracted = _extract_from_content(data)
        if extracted is not None:
            rows = extracted
        else:
            # บางกรณีอาจใช้ key อย่าง "rows", "data", "items", …
            for possible_key in ("rows", "data", "items"):
                maybe = data.get(possible_key)
                if isinstance(maybe, list):
                    rows = maybe
                    break

    # 4️⃣ ตอนนี้มี rows (list of dict) แล้ว ให้หาข้อมูลที่ name ตรงกับ target_name
    for record in rows:
        if isinstance(record, dict) and record.get("name") == target_name:
            # คืนค่าเป็น int (หรือ str หาก id เป็น string)
            return record.get("customer_id")

    # ไม่เจอ
    return None


# -------------------------------------------------
# 5️⃣ ตัวอย่างการใช้งาน
# -------------------------------------------------
if __name__ == "__main__":
    # ตัวอย่าง 1️⃣ ตามที่คุณให้มา (list ของ dict)
    json_result = [
        {
            "customer_id": 1,
            "name": "สมชาย ใจดี",
            "citizen_id": "1103700012345",
            "phone": "0812345678",
            "email": "somchai@example.com",
            "address": "99 หมู่ 1 ต.บางรัก อ.เมือง จ.กรุงเทพฯ 10500",
            "total_count": 1,
            "page": 1,
            "page_size": 1
        }
    ]

    cid = get_customer_id(json_result)
    print(f"🔍 customer_id ที่เจอ: {cid}")          # output: 1

    # ตัวอย่าง 2️⃣ โครงสร้างแบบ content.text
    json_with_content = {
        "content": [
            {
                "type": "text",
                "text": json.dumps({
                    "rows": [
                        {
                            "customer_id": 42,
                            "name": "สมชาย ใจดี",
                            "citizen_id": "1103700099999"
                        },
                        {
                            "customer_id": 99,
                            "name": "สมนึก",
                            "citizen_id": "1103700011111"
                        }
                    ]
                })
            }
        ]
    }

    cid2 = get_customer_id(json_with_content)
    print(f"🔍 customer_id จาก content.text: {cid2}")   # output: 42
```

### สรุปขั้นตอนที่ทำ

| ขั้นตอน | ทำอะไร |
|--------|--------|
| **1.** แปลง `raw_json` เป็น Python object (`dict`/`list`). | รองรับ input เป็น `str` หรือ object อยู่แล้ว |
| **2.** ตรวจสอบว่าเป็น **list** (กรณีที่คุณส่งมาโดยตรง) หรือ **dict** ที่มี key `content`. | หากเป็น `content.text` ให้ดึงข้อความ JSON ภายในและแปลงต่อ |
| **3.** หา **list of rows** (`rows`, `data`, `items` หรือจาก `content.text`). |
| **4.** วนลูปตรวจ `record["name"] == "สมชาย ใจดี"` → คืน `record["customer_id"]`. |
| **5.** หากไม่พบ → คืน `None`. |

คุณสามารถนำฟังก์ชัน `get_customer_id` ไปใช้ในโค้ดส่วนอื่นได้เลย หรือดัดแปลงให้รับพารามิเตอร์ `target_name` ต่าง ๆ ตามที่ต้องการ.  

ถ้ามีรูปแบบ JSON ที่แตกต่างจากที่กล่าวมา (เช่น ชื่อ key เปลี่ยน) เพียงเพิ่มเงื่อนไขในฟังก์ชัน `_extract_from_content` หรือในลูป `for possible_key in ("rows","data","items")` ก็จะจับได้ครับ.
